const fs = require('fs');
let lines = [];
try { lines = fs.readFileSync('/config/cyber-opportunities-sources.txt','utf8').split(/\r?\n/); } catch (e) {}
const urls = lines.map(function(l){ return l.trim(); }).filter(function(l){ return l && l.charAt(0) !== '#'; });
if (!urls.length) { return [{ json: { url: '' } }]; }
return urls.map(function(u){ return { json: { url: u } }; });

const items = $input.all();
const arts = items.map(function(i){ return i.json; }).filter(function(a){ return a && (a.title || a.contentSnippet || a.content); });
const regions = [
  ['UAE', /\buae\b|emirat|dubai|abu dhabi/i],
  ['Saudi Arabia', /saudi|\bksa\b|riyadh/i],
  ['Qatar', /qatar|doha/i],
  ['Oman', /\boman\b|muscat/i],
  ['Bahrain', /bahrain|manama/i],
  ['Kuwait', /kuwait/i],
  ['UK/Europe', /\buk\b|united kingdom|britain|europe|\beu\b|german|france|nato/i],
  ['Global', /./]
];
function detect(a){ var s=((a.title||'')+' '+(a.contentSnippet||a.content||'')).toString(); for(var i=0;i<regions.length;i++){ if(regions[i][1].test(s)) return regions[i][0]; } return 'Global'; }
function fmt(a){ var t=(a.title||'').toString(); var s=(a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,200); var u=(a.link||a.url||'').toString(); return '- ' + t + ' — ' + s + ' (' + u + ')'; }
var buckets={};
arts.forEach(function(a){ var k=detect(a); (buckets[k]=buckets[k]||[]).push(a); });
var order=Object.keys(buckets);
var per=5; var lines=[];
for(var r=0;r<per;r++){ for(var c=0;c<order.length;c++){ var arr=buckets[order[c]]; if(arr[r]){ lines.push('['+order[c]+'] '+fmt(arr[r])); } } }
var text = lines.length ? lines.join('\n') : 'No opportunity articles were retrieved this period.';
var previous='';
try {
  var fs=require('fs'); var dir='/reports/archive/cyber-opportunities';
  var today=new Date().toISOString().slice(0,10);
  var files=fs.readdirSync(dir).filter(function(fn){ return /cyber-opportunities-\d{4}-\d{2}-\d{2}\.json$/.test(fn) && fn.indexOf(today)===-1; }).sort();
  if(files.length){
    var prev=JSON.parse(fs.readFileSync(dir+'/'+files[files.length-1],'utf8'));
    var ple=[]; (prev.topOpportunities||[]).forEach(function(o){ ple.push('- '+(o.opportunity||'')+' ('+(o.buyer||'')+', '+(o.region||'')+')'); });
    previous='From '+files[files.length-1].replace('cyber-opportunities-','').replace('.json','')+':\n'+ple.join('\n');
  }
} catch(e){ previous=''; }
return [{ json: { articles: text, count: arts.length, date: new Date().toISOString().slice(0,10), previous: previous } }];

