const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /tender|rfp|rfi|soc|grc|opportunit|contract|security/i.test(l); }).slice(0,4).join('; ') || 'cybersecurity commercial opportunities in the GCC';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) with bright blue (#2E9BE6) accents. Abstract professional cyber/commercial motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Theme: ' + top } }];

let raw = ($json && $json.markdown) || '';
let data = null;
try { data = JSON.parse(raw); } catch (e) { try { var m = raw.match(/\{[\s\S]*\}/); if (m) { data = JSON.parse(m[0]); } } catch (e2) { data = null; } }
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function imgDataUri(base){ var tries=[['/config/branding/'+base+'.png','image/png'],['/config/branding/'+base+'.jpg','image/jpeg'],['/config/branding/'+base+'.jpeg','image/jpeg']]; for(var i=0;i<tries.length;i++){ try{ var b=fs.readFileSync(tries[i][0]); return 'data:'+tries[i][1]+';base64,'+b.toString('base64'); }catch(e){} } return ''; }
const coverSrc = imgDataUri('rfpcover');
const bannerSrc = imgDataUri('rfpbanner');
const avatarSrc = imgDataUri('jarvis-avatar');
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n + (s[(v-20)%10] || s[v] || s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g, function(c){ return ({ '&':'&amp;', '<':'&lt;', '>':'&gt;' })[c]; }); }
function pwColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0) return '#1E8E5A'; if(r.indexOf('med')===0) return '#B8860B'; if(r.indexOf('low')===0) return '#B02525'; return '#5A6472'; }
function h2(t){ return '<h2 style="color:#0A1A2F;border-left:4px solid #2E9BE6;padding-left:10px;font-family:Georgia,serif;font-size:18px;margin-top:26px">'+t+'</h2>'; }
function th(arr){ return '<tr style="background:#0A1A2F;color:#FFFFFF">'+arr.map(function(h){return '<th style="padding:8px;text-align:left;font-size:12px">'+h+'</th>';}).join('')+'</tr>'; }
function td(v,extra){ return '<td style="padding:8px;'+(extra||'')+'">'+esc(v)+'</td>'; }
function oppTable(rows){
  if(!rows||!rows.length) return '<p style="color:#5A6472">No opportunities identified this period.</p>';
  var head=th(['Opportunity','Buyer / Org','Region','Type','Est. Value','Deadline','Source']);
  var trs=rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">'+td(r.opportunity,'font-weight:600')+td(r.buyer)+td(r.region)+td(r.type)+td(r.value)+td(r.deadline)+td(r.source)+'</tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+head+trs+'</table>';
}
function hpTable(rows){
  if(!rows||!rows.length) return '<p style="color:#5A6472">No high-priority opportunities this period.</p>';
  var head=th(['Opportunity','Fit','Pursuit Posture','Win Probability']);
  var trs=rows.map(function(r){ return '<tr style="border-bottom:1px solid #E2E6EC;vertical-align:top">'+td(r.opportunity,'font-weight:600')+td(r.fit)+td(r.posture)+'<td style="padding:8px;color:'+pwColor(r.winProbability)+';font-weight:600">'+esc(r.winProbability)+'</td></tr>'; }).join('');
  return '<table style="border-collapse:collapse;width:100%;font-size:13px;margin:8px 0">'+head+trs+'</table>';
}
function regionList(rows){ if(!rows||!rows.length) return ''; return '<ul style="font-size:14px;line-height:1.6">'+rows.map(function(r){return '<li><strong>'+esc(r.region)+':</strong> '+esc(r.summary)+'</li>';}).join('')+'</ul>'; }
function actions(arr){ if(!arr||!arr.length) return ''; return '<ul style="font-size:14px;line-height:1.6">'+arr.map(function(a){return '<li>'+esc(a)+'</li>';}).join('')+'</ul>'; }
let body;
if(data){
  body = '<p style="font-size:15px">'+esc(data.executiveSummary||'')+'</p>' +
    (data.weekOverWeek ? ('<div style="background:#EAF4FC;border-left:4px solid #2E9BE6;padding:10px 12px;margin:12px 0;font-size:14px"><strong>What changed since last edition:</strong> '+esc(data.weekOverWeek)+'</div>') : '') +
    h2('Top Opportunities') + oppTable(data.topOpportunities) +
    h2('Regional Breakdown') + regionList(data.regionalBreakdown) +
    h2('High Priority Opportunities &amp; Win Probability') + hpTable(data.highPriority) +
    h2('Strategic Relevance') + '<p style="font-size:14px;line-height:1.6">'+esc(data.strategicRelevance||'')+'</p>' +
    h2('Recommended Actions') + actions(data.recommendedActions) +
    h2('Historical Trends') + '<p style="font-size:14px;line-height:1.6">'+esc(data.historicalTrends||'')+'</p>';
} else {
  body = '<div style="padding:12px;background:#FDECEC;border:1px solid #B02525;color:#7a1a1a;border-radius:4px">The analyst did not return structured data this run. Raw output below.</div><pre style="white-space:pre-wrap;font-family:inherit">'+esc(raw)+'</pre>';
}
const weekOf = (data && data.weekOf) ? data.weekOf : date;
const frontCover = coverSrc ? ('<div style="position:relative;height:100vh;page-break-after:always;overflow:hidden">' + '<img src="'+coverSrc+'" style="width:100%;height:100%;object-fit:cover;display:block"/>' + '<div style="position:absolute;top:26px;right:30px;color:#FFFFFF;font-family:Georgia,serif;font-size:22px;font-weight:700;text-shadow:0 1px 5px rgba(0,0,0,0.7)">'+esc(prettyDate(date))+'</div>' + '</div>') : '';
const masthead = bannerSrc ? ('<img src="'+bannerSrc+'" style="width:100%;display:block"/>') : ('<div style="background:#0A1A2F;color:#FFFFFF;padding:18px;font-family:Georgia,serif;font-size:20px">JARVIS INTELLIGENCE — Cyber Opportunities Brief</div>');
const signoff = avatarSrc ? ('<div style="text-align:center;padding:20px;border-top:3px solid #2E9BE6;margin-top:16px"><img src="'+avatarSrc+'" style="width:104px;height:104px;border-radius:50%;border:2px solid #2E9BE6"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>') : '';
const html = '<!doctype html><meta charset="utf-8"><title>Cyber Opportunities Brief — '+esc(weekOf)+'</title>' +
  '<div style="font-family:-apple-system,Segoe UI,Arial,sans-serif;color:#11151c;max-width:980px;margin:0 auto">' +
  frontCover + masthead +
  '<div style="background:#05101F;color:#cdd5e0;padding:6px 18px;font-size:13px">'+esc(weekOf)+' &nbsp;·&nbsp; Confidential</div>' +
  '<div style="padding:28px">'+body+'</div>' + signoff + '</div>';
return [{ json: { date: date, html: html, markdown: raw } }];

const fs = require('fs');
const date = $json.date; const html = $json.html; const md = $json.markdown || '';
const dirs = ['/reports/cyber-opportunities', '/reports/archive/cyber-opportunities'];
for (var k=0;k<dirs.length;k++){ try { fs.mkdirSync(dirs[k],{recursive:true}); fs.writeFileSync(dirs[k]+'/cyber-opportunities-'+date+'.html', html); } catch(e){} }
try { fs.writeFileSync('/reports/archive/cyber-opportunities/cyber-opportunities-'+date+'.json', md); } catch(e){}
try { fs.writeFileSync('/logs/last-run-success.txt', new Date().toISOString()+' cyber-opportunities'); } catch(e){}
return [{ json: $json }];

var queries = [
  'cybersecurity (tender OR RFP OR RFI OR procurement) (UAE OR "Saudi Arabia" OR Qatar OR Oman OR Bahrain OR Kuwait)',
  '("managed security" OR SOC OR GRC OR "vulnerability management") (tender OR RFP OR contract) (UAE OR Gulf OR "Saudi Arabia" OR Qatar)',
  '("OT security" OR "critical infrastructure" OR "cloud security" OR "AI security") (tender OR RFP) (Gulf OR UAE OR "Middle East")',
  'cybersecurity (tender OR framework OR RFP OR procurement) ("United Kingdom" OR UK OR Europe)'
];
return queries.map(function(q){ return { json: { q: q } }; });

const items = $input.all();
var links = [];
items.forEach(function(it){
  var arr = (it.json && it.json.items) ? it.json.items : [];
  arr.forEach(function(r){ links.push('- ' + (r.title||'') + ' — ' + ((r.snippet||'').toString().replace(/\s+/g,' ').slice(0,160)) + ' (' + (r.link||'') + ')'); });
});
var text = links.length ? links.slice(0,25).join('\n') : 'No verified tender links retrieved (set GOOGLE_CSE_KEY and GOOGLE_CSE_CX in .env to enable real RFP links).';
return [{ json: { tenders: text, tenderCount: links.length } }];

const items=$input.all();
const date=$('Render HTML').first().json.date;
items.forEach(function(it){ if(it.binary && it.binary.data){ it.binary.data.fileName='cyber-opportunities-'+date+'.pdf'; } });
return items;
